    fbBuilder.addFloat64(17, _VTEC);
    fbBuilder.addFloat64(18, _STEC);
    fbBuilder.addFloat64(19, _S4);
    fbBuilder.addOffset(20, DATA_POINTSOffset);
    fbBuilder.addOffset(21, DENSITY_PROFILESOffset);
    fbBuilder.addUint8(22, _QUALITY);
    fbBuilder.addOffset(23, NOTESOffset);
    return fbBuilder.endTable();
  }

  /// Convenience method to serialize to byte list.
  @override
  Uint8List toBytes([String? fileIdentifier]) {
    final fbBuilder = fb.Builder(deduplicateTables: false);
    fbBuilder.finish(finish(fbBuilder), fileIdentifier);
    return fbBuilder.buffer;
  }
}
